function getStreamingTheoryPrompt(topicName: string, courseTitle: string, context: string, domain: Domain): string {
  const domainHints: Record<Domain, string> = {
    PROGRAMMING: 'Включи рабочие примеры кода с комментариями, паттерны и антипаттерны.',
    MATHEMATICS: 'Формулы в LaTeX, пошаговые выводы, геометрическая интуиция.',
    PHYSICS: 'Формулы в LaTeX, физическая интуиция, мысленные эксперименты, единицы СИ.',
    CHEMISTRY: 'Уравнения реакций, молекулярные структуры, практические примеры.',
    BIOLOGY: 'Схемы процессов, классификации, сравнительные таблицы.',
    HISTORY: 'Даты, причинно-следственные связи, исторический контекст.',
    LANGUAGES: 'Примеры использования, грамматические правила, сравнения.',
    ECONOMICS: 'Графики, формулы, экономические модели, реальные данные.',
    ARTS: 'Примеры произведений, анализ стилей, контекст эпохи.',
    MEDICINE: 'Анатомические детали, клинические примеры, доказательная медицина.',
    LAW: 'Ссылки на законы, судебную практику.',
    ENGINEERING: 'Технические расчёты, схемы, стандарты.',
    GENERAL: 'Адаптируй под тему.',
  }

  const hint = domainHints[domain] || domainHints.GENERAL

  return `Тема: "${topicName}"
Курс: ${courseTitle}
Домен: ${domain}

${hint}

${context ? `[ДОПОЛНИТЕЛЬНЫЕ ИСТОЧНИКИ]:
${context}
` : ''}
Напиши лекцию по структуре из system prompt.

ДОПОЛНИТЕЛЬНЫЕ УКАЗАНИЯ:
- Год сейчас: 2026. Если тема устарела — честно скажи и объясни, зачем её всё равно нужно знать
- Сравнительные таблицы — обязательно, где есть что сравнивать
- Код должен быть рабочим и копируемым
- LaTeX формулы НЕ внутри ячеек таблиц (рендерятся криво), только до/после таблицы
- Интерактивные quiz-блоки вместо текстовых вопросов с ответами`
}

