'use client'

import { useState } from 'react'
import { CheckCircle, XCircle, HelpCircle } from 'lucide-react'
import { Button } from '@/components/ui'
import { cn } from '@/lib/utils'

interface QuizQuestionProps {
  question: string
  options: string[]
  correctAnswer: number
  explanation: string
  onAnswer: (isCorrect: boolean) => void
  onNext?: () => void // Optional - if provided, shows "Next" button
  showNextButton?: boolean // Control visibility of next button
}

export function QuizQuestion({
  question,
  options,
  correctAnswer,
  explanation,
  onAnswer,
  onNext,
  showNextButton = false,
}: QuizQuestionProps) {
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null)
  const [isSubmitted, setIsSubmitted] = useState(false)
  const [showExplanation, setShowExplanation] = useState(false)

  const isCorrect = selectedAnswer === correctAnswer

  const handleSubmit = () => {
    if (selectedAnswer === null) return
    setIsSubmitted(true)
    setShowExplanation(true)
    onAnswer(isCorrect)
  }

  const handleNext = () => {
    setSelectedAnswer(null)
    setIsSubmitted(false)
    setShowExplanation(false)
    onNext?.()
  }

  return (
    <div className="bg-slate-800/50 rounded-xl border border-slate-700/50 p-6">
      {/* Question */}
      <div className="flex items-start gap-3 mb-6">
        <HelpCircle className="w-6 h-6 text-primary-400 flex-shrink-0 mt-1" />
        <h3 className="text-lg font-medium text-white">{question}</h3>
      </div>

      {/* Options */}
      <div className="space-y-3 mb-6">
        {options.map((option, index) => {
          const isSelected = selectedAnswer === index
          const isCorrectOption = index === correctAnswer
          
          let optionStyle = 'border-slate-600/50 hover:border-slate-500'
          if (isSubmitted) {
            if (isCorrectOption) {
              optionStyle = 'border-green-500 bg-green-500/10'
            } else if (isSelected && !isCorrectOption) {
              optionStyle = 'border-red-500 bg-red-500/10'
            }
          } else if (isSelected) {
            optionStyle = 'border-primary-500 bg-primary-500/10'
          }

          return (
            <button
              key={index}
              onClick={() => !isSubmitted && setSelectedAnswer(index)}
              disabled={isSubmitted}
              className={cn(
                'w-full flex items-center gap-3 p-4 rounded-lg border-2 transition-all text-left',
                optionStyle,
                !isSubmitted && 'cursor-pointer'
              )}
            >
              <div
                className={cn(
                  'w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium',
                  isSubmitted && isCorrectOption
                    ? 'bg-green-500 text-white'
                    : isSubmitted && isSelected && !isCorrectOption
                    ? 'bg-red-500 text-white'
                    : isSelected
                    ? 'bg-primary-500 text-white'
                    : 'bg-slate-700 text-slate-300'
                )}
              >
                {String.fromCharCode(65 + index)}
              </div>
              <span className="text-slate-200 flex-1">{option}</span>
              {isSubmitted && isCorrectOption && (
                <CheckCircle className="w-5 h-5 text-green-400" />
              )}
              {isSubmitted && isSelected && !isCorrectOption && (
                <XCircle className="w-5 h-5 text-red-400" />
              )}
            </button>
          )
        })}
      </div>

      {/* Explanation */}
      {showExplanation && (
        <div
          className={cn(
            'p-4 rounded-lg mb-6',
            isCorrect ? 'bg-green-500/10 border border-green-500/30' : 'bg-red-500/10 border border-red-500/30'
          )}
        >
          <div className="flex items-center gap-2 mb-2">
            {isCorrect ? (
              <>
                <CheckCircle className="w-5 h-5 text-green-400" />
                <span className="font-medium text-green-400">Правильно!</span>
              </>
            ) : (
              <>
                <XCircle className="w-5 h-5 text-red-400" />
                <span className="font-medium text-red-400">Неправильно</span>
              </>
            )}
          </div>
          <p className="text-slate-300 text-sm">{explanation}</p>
        </div>
      )}

      {/* Actions */}
      <div className="flex gap-3">
        {!isSubmitted ? (
          <Button
            onClick={handleSubmit}
            disabled={selectedAnswer === null}
            className="flex-1"
          >
            Ответить
          </Button>
        ) : showNextButton ? (
          <Button onClick={handleNext} className="flex-1">
            Следующий вопрос
          </Button>
        ) : null}
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { CheckCircle, Eye, Lightbulb, ChevronDown, ChevronUp } from 'lucide-react'
import { Button } from '@/components/ui'

interface VisualTaskProps {
  title: string
  description: string
  steps?: string[]
  expectedResult: string
  hints?: string[]
  checkpoints?: string[]
  onComplete: () => void
  isLoading?: boolean
}

export function VisualTask({
  title,
  description,
  steps = [],
  expectedResult,
  hints = [],
  checkpoints = [],
  onComplete,
  isLoading,
}: VisualTaskProps) {
  const [completedSteps, setCompletedSteps] = useState<Set<number>>(new Set())
  const [showResult, setShowResult] = useState(false)
  const [showHints, setShowHints] = useState(false)
  const [currentHint, setCurrentHint] = useState(0)

  const toggleStep = (index: number) => {
    const newSet = new Set(completedSteps)
    if (newSet.has(index)) {
      newSet.delete(index)
    } else {
      newSet.add(index)
    }
    setCompletedSteps(newSet)
  }

  const allStepsCompleted = steps.length > 0 && completedSteps.size === steps.length

  const showNextHint = () => {
    if (currentHint < hints.length) {
      setCurrentHint(prev => prev + 1)
      setShowHints(true)
    }
  }

  return (
    <div className="space-y-6">
      {/* Task description */}
      <div className="bg-slate-800/50 rounded-xl p-6 border border-slate-700/50">
        <h3 className="text-lg font-semibold text-white mb-3">{title}</h3>
        <p className="text-slate-300 whitespace-pre-wrap">{description}</p>
      </div>

      {/* Steps */}
      {steps.length > 0 && (
        <div className="bg-slate-800/50 rounded-xl p-6 border border-slate-700/50">
          <h4 className="text-md font-semibold text-white mb-4">Пошаговая инструкция:</h4>
          <div className="space-y-3">
            {steps.map((step, index) => (
              <div
                key={index}
                onClick={() => toggleStep(index)}
                className={`flex items-start gap-3 p-3 rounded-lg cursor-pointer transition-colors ${
                  completedSteps.has(index)
                    ? 'bg-green-500/10 border border-green-500/30'
                    : 'bg-slate-900/50 hover:bg-slate-900'
                }`}
              >
                <div className={`w-6 h-6 rounded-full flex items-center justify-center flex-shrink-0 ${
                  completedSteps.has(index)
                    ? 'bg-green-500 text-white'
                    : 'bg-slate-700 text-slate-400'
                }`}>
                  {completedSteps.has(index) ? (
                    <CheckCircle className="w-4 h-4" />
                  ) : (
                    <span className="text-sm">{index + 1}</span>
                  )}
                </div>
                <span className={completedSteps.has(index) ? 'text-green-300' : 'text-slate-300'}>
                  {step}
                </span>
              </div>
            ))}
          </div>
          <p className="text-sm text-slate-500 mt-4">
            Отмечай выполненные шаги, кликая на них
          </p>
        </div>
      )}

      {/* Checkpoints */}
      {checkpoints.length > 0 && (
        <div className="bg-slate-800/50 rounded-xl p-6 border border-slate-700/50">
          <h4 className="text-md font-semibold text-white mb-4">Проверь себя:</h4>
          <ul className="space-y-2">
            {checkpoints.map((checkpoint, index) => (
              <li key={index} className="flex items-start gap-2 text-slate-300">
                <span className="text-primary-400">✓</span>
                {checkpoint}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Hints */}
      {hints.length > 0 && (
        <div className="bg-yellow-500/10 rounded-xl p-4 border border-yellow-500/30">
          <button
            onClick={showNextHint}
            className="flex items-center gap-2 text-yellow-400 hover:text-yellow-300 transition-colors"
          >
            <Lightbulb className="w-5 h-5" />
            <span>Подсказка ({Math.min(currentHint + 1, hints.length)}/{hints.length})</span>
          </button>
          {showHints && currentHint > 0 && (
            <div className="mt-4 space-y-2">
              {hints.slice(0, currentHint).map((hint, index) => (
                <p key={index} className="text-slate-300 pl-7">
                  {index + 1}. {hint}
                </p>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Expected result */}
      <div className="bg-slate-800/50 rounded-xl border border-slate-700/50 overflow-hidden">
        <button
          onClick={() => setShowResult(!showResult)}
          className="w-full flex items-center justify-between p-4 text-left hover:bg-slate-800/80 transition-colors"
        >
          <div className="flex items-center gap-2">
            <Eye className="w-5 h-5 text-primary-400" />
            <span className="font-medium text-white">Как должен выглядеть результат</span>
          </div>
          {showResult ? (
            <ChevronUp className="w-5 h-5 text-slate-400" />
          ) : (
            <ChevronDown className="w-5 h-5 text-slate-400" />
          )}
        </button>
        {showResult && (
          <div className="p-4 pt-0 border-t border-slate-700/50">
            <p className="text-slate-300 whitespace-pre-wrap">{expectedResult}</p>
          </div>
        )}
      </div>

      {/* Complete button */}
      <Button
        onClick={onComplete}
        isLoading={isLoading}
        className="w-full"
        disabled={steps.length > 0 && !allStepsCompleted}
        leftIcon={<CheckCircle className="w-5 h-5" />}
      >
        {allStepsCompleted || steps.length === 0 ? 'Задание выполнено' : `Выполни все шаги (${completedSteps.size}/${steps.length})`}
      </Button>
    </div>
  )
}

